#include <stdio.h>
#include <sys/stat.h>
#include <unistd.h>

/* == EXEMPLE ================================================
 * Verifier les permissions d'un repertoire
 * st_mode & 0777 extrait les bits rwxrwxrwx
 * S_IRUSR, S_IWUSR, S_IXUSR = bits du proprietaire
 * =========================================================== */
void example_check_perms(void) {
    struct stat sb;
    stat("/tmp", &sb);
    printf("Permissions /tmp : %o\n", sb.st_mode & 0777);
    printf("Ecriture tous : %d\n", (sb.st_mode & S_IWOTH) ? 1 : 0);
    printf("Sticky bit : %d\n", (sb.st_mode & S_ISVTX) ? 1 : 0);
}
/* Resultat: Permissions /tmp : 1777, Ecriture tous : 1, Sticky: 1 */

